query:
-- 1. Corrigir comissão: dividir por 100 onde valor > 10 (estava multiplicado por 100)
UPDATE pro_rata SET comissao = comissao / 100 WHERE comissao > 10;

-- 2. Recalcular VLR = comissao * qtdFaltaReceber para todos os registros
UPDATE pro_rata SET vlr = comissao * qtdFaltaReceber WHERE qtdFaltaReceber IS NOT NULL AND comissao IS NOT NULL;

-- 3. Converter data serial do Excel para formato DD/MM/AAAA
-- Serial do Excel: dias desde 30/12/1899. Converter para DATE e formatar.
UPDATE pro_rata 
SET dataFinal = DATE_FORMAT(DATE_ADD('1899-12-30', INTERVAL CAST(dataFinal AS UNSIGNED) DAY), '%d/%m/%Y')
WHERE dataFinal REGEXP '^[0-9]{4,5}$';

